<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>VoidTerminal — ShadowRig OS</title>

    <!-- Tailwind CSS -->
    <script src="https://cdn.tailwindcss.com"></script>

    <!-- Leaflet CSS -->
    <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/leaflet.draw/1.0.4/leaflet.draw.css" />

    <!-- xterm.js CSS -->
    <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/xterm@5.3.0/css/xterm.css" />

    <style>
        /* SHADOWRIG THEME */
        :root {
            --emerald-glow: #10b981;
            --matrix-green: #00ff41;
            --terminal-bg: #0a0a0a;
        }

        body {
            background-color: #000;
            color: var(--emerald-glow);
            font-family: 'Courier New', monospace;
            overflow: hidden;
            margin: 0;
            height: 100vh;
        }

        /* CRT scanline overlay */
        .scanlines {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: linear-gradient(
                to bottom,
                rgba(0, 0, 0, 0) 50%,
                rgba(0, 255, 65, 0.03) 50%
            );
            background-size: 100% 4px;
            pointer-events: none;
            z-index: 9999;
        }

        /* Matrix rain canvas */
        #matrix-rain {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            z-index: 1;
            opacity: 0.15;
            pointer-events: none;
        }

        /* Desktop icons */
        .desktop-icon {
            position: absolute;
            width: 80px;
            text-align: center;
            cursor: grab;
            user-select: none;
            transition: transform 0.2s;
        }

        .desktop-icon:active {
            cursor: grabbing;
            transform: scale(0.95);
        }

        .desktop-icon-img {
            width: 48px;
            height: 48px;
            margin: 0 auto 4px;
            background: rgba(16, 185, 129, 0.2);
            border: 1px solid var(--emerald-glow);
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 24px;
        }

        .desktop-icon-label {
            font-size: 11px;
            color: var(--emerald-glow);
            text-shadow: 0 0 5px var(--emerald-glow);
            background: rgba(0, 0, 0, 0.6);
            padding: 2px 6px;
            border-radius: 3px;
        }

        /* Terminal fullscreen */
        #terminal-container {
            position: fixed;
            top: 0;
            left: 0;
            width: 100vw;
            height: 100vh;
            background: #000;
            z-index: 10000;
            display: none;
        }

        /* Modal for map tagging */
        .modal {
            position: fixed;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            background: rgba(10, 10, 10, 0.95);
            border: 1px solid var(--emerald-glow);
            border-radius: 8px;
            padding: 20px;
            z-index: 1000;
            display: none;
            max-width: 500px;
            width: 90%;
            box-shadow: 0 0 30px rgba(16, 185, 129, 0.3);
        }

        .modal.active {
            display: block;
        }

        .modal-backdrop {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0, 0, 0, 0.7);
            z-index: 999;
            display: none;
        }

        .modal-backdrop.active {
            display: block;
        }

        /* Glitch effect on terminal */
        @keyframes glitch {
            0% { transform: translate(0) }
            20% { transform: translate(-2px, 2px) }
            40% { transform: translate(-2px, -2px) }
            60% { transform: translate(2px, 2px) }
            80% { transform: translate(2px, -2px) }
            100% { transform: translate(0) }
        }

        .glitch {
            animation: glitch 0.3s infinite;
        }

        /* Scrollbar */
        ::-webkit-scrollbar {
            width: 8px;
        }

        ::-webkit-scrollbar-track {
            background: #000;
        }

        ::-webkit-scrollbar-thumb {
            background: var(--emerald-glow);
            border-radius: 4px;
        }
    </style>
</head>
<body>
    <!-- Background Effects -->
    <canvas id="matrix-rain"></canvas>
    <div class="scanlines"></div>

    <!-- Desktop Icons -->
    <div class="desktop-icon" id="icon-map" style="top: 20px; left: 20px;">
        <div class="desktop-icon-img">🗺️</div>
        <div class="desktop-icon-label">Map</div>
    </div>

    <div class="desktop-icon" id="icon-terminal" style="top: 20px; left: 120px;">
        <div class="desktop-icon-img">💻</div>
        <div class="desktop-icon-label">Terminal</div>
    </div>

    <div class="desktop-icon" id="icon-botnet" style="top: 20px; left: 220px;">
        <div class="desktop-icon-img">🕸️</div>
        <div class="desktop-icon-label">Botnet</div>
    </div>

    <div class="desktop-icon" id="icon-market" style="top: 20px; left: 320px;">
        <div class="desktop-icon-img">🏪</div>
        <div class="desktop-icon-label">Market</div>
    </div>

    <div class="desktop-icon" id="icon-logs" style="top: 20px; left: 420px;">
        <div class="desktop-icon-img">📋</div>
        <div class="desktop-icon-label">Logs</div>
    </div>

    <!-- Map Container (hidden initially) -->
    <div id="map-container" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; z-index: 100; display: none;">
        <div class="absolute top-4 left-4 z-[400] bg-black/80 border border-emerald-500 rounded p-3">
            <button id="close-map" class="text-emerald-400 hover:text-emerald-300 font-bold">✕ Close Map</button>
            <button id="draw-zone-btn" class="ml-4 bg-emerald-900/50 border border-emerald-500 text-emerald-400 px-4 py-2 rounded hover:bg-emerald-900/70">
                Claim Territory
            </button>
            <span class="ml-4 text-emerald-500 text-sm">| Drag to draw polygon</span>
        </div>
        <div id="map" style="width: 100%; height: 100%;"></div>
    </div>

    <!-- Terminal Container -->
    <div id="terminal-container">
        <div class="absolute top-4 right-4 z-[400]">
            <button id="close-terminal" class="text-emerald-400 hover:text-emerald-300 font-bold text-xl">✕</button>
        </div>
        <div id="terminal" style="width: 100%; height: 100%;"></div>
    </div>

    <!-- Botnet Container -->
    <div id="botnet-container" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; z-index: 100; background: #000; display: none;">
        <div class="absolute top-4 left-4 z-[400] bg-black/80 border border-emerald-500 rounded p-3">
            <button id="close-botnet" class="text-emerald-400 hover:text-emerald-300 font-bold">✕ Close Botnet</button>
        </div>
        <div class="flex items-center justify-center h-full">
            <div class="text-center">
                <h2 class="text-2xl text-emerald-400 mb-4">BOTNET DASHBOARD</h2>
                <p class="text-emerald-600">Owned APs: <span id="owned-count">0</span></p>
                <p class="text-emerald-600">Total Income Rate: <span id="income-rate">0</span> credits/sec</p>
                <p class="text-emerald-600">Last Payout: <span id="last-payout">never</span></p>
                <button id="simulate-payout" class="mt-4 bg-emerald-900/50 border border-emerald-500 text-emerald-400 px-6 py-2 rounded hover:bg-emerald-900/70">
                    Simulate Payout
                </button>
            </div>
        </div>
    </div>

    <!-- Market Container -->
    <div id="market-container" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; z-index: 100; background: #000; display: none;">
        <div class="absolute top-4 left-4 z-[400] bg-black/80 border border-emerald-500 rounded p-3">
            <button id="close-market" class="text-emerald-400 hover:text-emerald-300 font-bold">✕ Close Market</button>
        </div>
        <div class="flex items-center justify-center h-full">
            <div class="text-center max-w-2xl">
                <h2 class="text-2xl text-emerald-400 mb-6">DARKWEB MARKET</h2>
                <div id="tools-list" class="grid grid-cols-2 gap-4 text-left">
                    <!-- Tools will be rendered here -->
                </div>
            </div>
        </div>
    </div>

    <!-- Logs Container -->
    <div id="logs-container" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; z-index: 100; background: #000; display: none;">
        <div class="absolute top-4 left-4 z-[400] bg-black/80 border border-emerald-500 rounded p-3">
            <button id="close-logs" class="text-emerald-400 hover:text-emerald-300 font-bold">✕ Close Logs</button>
        </div>
        <div class="p-4 h-full overflow-auto">
            <h2 class="text-xl text-emerald-400 mb-4">SYSTEM LOGS</h2>
            <div id="logs-content" class="text-emerald-600 font-mono text-sm space-y-1"></div>
        </div>
    </div>

    <!-- Upload Modal (for testing) -->
    <div class="modal-backdrop" id="upload-backdrop"></div>
    <div class="modal" id="upload-modal">
        <h3 class="text-xl text-emerald-400 mb-4">UPLOAD WARDRIVE DATA</h3>
        <form id="upload-form" class="space-y-4">
            <div>
                <label class="block text-emerald-500 mb-2">Select CSV or JSON file:</label>
                <input type="file" name="file" accept=".csv,.json" class="w-full bg-black/50 border border-emerald-500 rounded px-3 py-2 text-emerald-300" required>
            </div>
            <button type="submit" class="w-full bg-emerald-900/50 border border-emerald-500 text-emerald-400 py-2 rounded hover:bg-emerald-900/70">
                UPLOAD
            </button>
            <button type="button" id="cancel-upload" class="w-full mt-2 text-emerald-600 hover:text-emerald-400">
                Cancel
            </button>
        </form>
        <div id="upload-status" class="mt-4 text-emerald-300 hidden"></div>
    </div>

    <!-- AP Tagging Modal -->
    <div class="modal-backdrop" id="tag-backdrop"></div>
    <div class="modal" id="tag-modal">
        <h3 class="text-xl text-emerald-400 mb-4">TAG ACCESS POINT</h3>
        <div class="space-y-4">
            <div>
                <label class="block text-emerald-500 mb-2">BSSID:</label>
                <div id="tag-bssid" class="text-emerald-300 font-mono bg-black/50 border border-emerald-500 rounded px-3 py-2"></div>
            </div>
            <div>
                <label class="block text-emerald-500 mb-2">SSID:</label>
                <div id="tag-ssid" class="text-emerald-300 bg-black/50 border border-emerald-500 rounded px-3 py-2"></div>
            </div>
            <div>
                <label class="block text-emerald-500 mb-2">Manual Tag / Notes:</label>
                <textarea id="tag-notes" class="w-full bg-black/50 border border-emerald-500 rounded px-3 py-2 text-emerald-300" rows="3" placeholder="Add notes..."></textarea>
            </div>
            <div class="flex space-x-2">
                <button id="save-tag" class="flex-1 bg-emerald-900/50 border border-emerald-500 text-emerald-400 py-2 rounded hover:bg-emerald-900/70">
                    SAVE
                </button>
                <button id="cancel-tag" class="flex-1 text-emerald-600 hover:text-emerald-400 py-2">
                    CANCEL
                </button>
            </div>
        </div>
    </div>

    <!-- JavaScript -->
    <script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/leaflet.draw/1.0.4/leaflet.draw.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/xterm@5.3.0/lib/xterm.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/xterm-addon-fit@0.8.0/lib/xterm-addon-fit.js"></script>

    <script>
        // Matrix rain effect
        (function() {
            const canvas = document.getElementById('matrix-rain');
            const ctx = canvas.getContext('2d');

            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;

            const chars = '01';
            const fontSize = 14;
            const columns = canvas.width / fontSize;
            const drops = Array(Math.floor(columns)).fill(1);

            function draw() {
                ctx.fillStyle = 'rgba(0, 0, 0, 0.05)';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
                ctx.fillStyle = '#00ff41';
                ctx.font = fontSize + 'px monospace';

                for (let i = 0; i < drops.length; i++) {
                    const text = chars[Math.floor(Math.random() * chars.length)];
                    ctx.fillText(text, i * fontSize, drops[i] * fontSize);

                    if (drops[i] * fontSize > canvas.height && Math.random() > 0.975) {
                        drops[i] = 0;
                    }
                    drops[i]++;
                }
            }

            setInterval(draw, 50);

            window.addEventListener('resize', () => {
                canvas.width = window.innerWidth;
                canvas.height = window.innerHeight;
            });
        })();

        // Desktop icon dragging
        let draggedIcon = null;
        let dragOffsetX = 0;
        let dragOffsetY = 0;

        document.querySelectorAll('.desktop-icon').forEach(icon => {
            icon.addEventListener('mousedown', function(e) {
                draggedIcon = this;
                const rect = this.getBoundingClientRect();
                dragOffsetX = e.clientX - rect.left;
                dragOffsetY = e.clientY - rect.top;
                this.style.zIndex = 1000;
            });
        });

        document.addEventListener('mousemove', function(e) {
            if (draggedIcon) {
                draggedIcon.style.left = (e.clientX - dragOffsetX) + 'px';
                draggedIcon.style.top = (e.clientY - dragOffsetY) + 'px';
            }
        });

        document.addEventListener('mouseup', function() {
            if (draggedIcon) {
                draggedIcon.style.zIndex = '';
                draggedIcon = null;
            }
        });

        // Map functionality
        let map = null;
        let drawnItems = null;
        let drawControl = null;

        document.getElementById('icon-map').addEventListener('dblclick', () => {
            document.getElementById('map-container').style.display = 'block';
            if (!map) {
                map = L.map('map').setView([43.9147, -70.0665], 13); // Lewiston, Maine
                L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
                    attribution: '&copy; OpenStreetMap contributors &copy; CARTO',
                    maxZoom: 19
                }).addTo(map);

                drawnItems = new L.FeatureGroup();
                map.addLayer(drawnItems);

                // Load existing APs and zones
                fetch('/api/map')
                    .then(res => res.json())
                    .then(data => {
                        // Render APs as markers
                        data.access_points.forEach(ap => {
                            const marker = L.marker([ap.lat, ap.lon]).addTo(map);
                            marker.bindPopup(`<b>${ap.ssid}</b><br>BSSID: ${ap.bssid}<br>Tier: ${ap.tier}<br>Vuln: ${ap.vuln_score}`);
                        });

                        // Render zones as polygons
                        data.zones.forEach(zone => {
                            const polygon = L.polygon(zone.geojson.coordinates[0], {
                                color: getZoneColor(zone.type),
                                fillOpacity: zone.opacity
                            }).addTo(map);
                            polygon.bindPopup(`<b>${zone.name}</b><br>Type: ${zone.type}`);
                        });
                    });
            }
        });

        document.getElementById('close-map').addEventListener('click', () => {
            document.getElementById('map-container').style.display = 'none';
        });

        function getZoneColor(type) {
            const colors = {
                'hospital': '#ff0000',
                'school': '#0000ff',
                'industrial': '#ffa500',
                'other': '#808080'
            };
            return colors[type] || '#808080';
        }

        // Zone drawing
        let drawingEnabled = false;
        document.getElementById('draw-zone-btn').addEventListener('click', function() {
            drawingEnabled = !drawingEnabled;
            if (drawingEnabled) {
                this.classList.add('bg-emerald-500', 'text-black');
                this.textContent = 'Drawing... (click map to draw)';
                // Enable Leaflet.Draw polygon
                if (!drawControl) {
                    drawControl = new L.Control.Draw({
                        draw: {
                            polygon: {
                                allowIntersection: false,
                                showArea: true
                            },
                            polyline: false,
                            rectangle: true,
                            circle: false,
                            marker: false,
                            circlemarker: false
                        },
                        edit: {
                            featureGroup: drawnItems
                        }
                    });
                    map.addControl(drawControl);
                }
            } else {
                this.classList.remove('bg-emerald-500', 'text-black');
                this.textContent = 'Claim Territory';
            }
        });

        // Terminal functionality
        let term = null;
        let fitAddon = null;

        document.getElementById('icon-terminal').addEventListener('dblclick', () => {
            document.getElementById('terminal-container').style.display = 'block';
            if (!term) {
                term = new Terminal({
                    cursorBlink: true,
                    theme: {
                        background: '#000000',
                        foreground: '#10b981',
                        cursor: '#10b981'
                    },
                    fontFamily: 'Courier New, monospace',
                    fontSize: 14
                });
                fitAddon = new FitAddon.FitAddon();
                term.loadAddon(fitAddon);
                term.open(document.getElementById('terminal'));
                fitAddon.fit();

                term.writeln('\x1b[32m\x1b[1m█▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀▀█');
                term.writeln('\x1b[32m\x1b[1m█  \x1b[33mVOIDTERMINAL v0.8 — SHADOWRIG OS\x1b[32m\x1b[1m  █');
                term.writeln('\x1b[32m\x1b[1m█▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄▄█');
                term.writeln('');
                term.writeln('\x1b[36m> System initialized...');
                term.writeln('\x1b[36m> Loading botnet modules...');
                term.writeln('\x1b[36m> Ready.\x1b[0m');
                term.writeln('');
                term.prompt = () => {
                    term.write('\x1b[32m┌─[\x1b[33mroot@shadowrig\x1b[32m]─[\x1b[33m~/botnet\x1b[32m]\n\x1b[32m└─$\x1b[0m ');
                };
                term.prompt();

                term.onData(async (data) => {
                    const input = data.trim();
                    if (input === '') {
                        term.prompt();
                        return;
                    }
                    term.writeln('');
                    await handleCommand(input);
                    term.prompt();
                });
            }
        });

        async function handleCommand(cmd) {
            // Echo command
            term.writeln(`\x1b[33m> ${cmd}\x1b[0m`);

            const parts = cmd.split(' ');
            const command = parts[0].toLowerCase();

            try {
                switch (command) {
                    case 'status':
                        const statusRes = await fetch('/api/status').then(r => r.json());
                        term.writeln(`\x1b[36mCredits: ${statusRes.credits}`);
                        term.writeln(`Reputation: ${statusRes.reputation}`);
                        term.writeln(`Heat Level: ${statusRes.heat_level}/100`);
                        term.writeln(`Owned APs: ${statusRes.owned_aps}`);
                        term.writeln(`Income Rate: ${statusRes.income_rate} cr/sec`);
                        break;

                    case 'targets':
                        const targetsRes = await fetch('/api/targets').then(r => r.json());
                        term.writeln(`\x1b[36mAvailable targets (${targetsRes.count}):`);
                        targetsRes.targets.forEach((t, i) => {
                            term.writeln(`  ${i+1}. ${t.ssid} (${t.bssid}) - Tier: ${t.tier}, Vuln: ${t.vuln_score}`);
                        });
                        break;

                    case 'breach':
                        if (parts.length < 2) {
                            term.writeln('\x1b[31mUsage: breach <bssid>\x1b[0m');
                            break;
                        }
                        const breachRes = await fetch('/api/breach', {
                            method: 'POST',
                            headers: {'Content-Type': 'application/json'},
                            body: JSON.stringify({bssid: parts[1]})
                        }).then(r => r.json());
                        if (breachRes.success) {
                            term.writeln(`\x1b[32m[+] Successfully breached ${parts[1]}`);
                            term.writeln(`    Payload installed: ${breachRes.payload}`);
                            term.writeln(`    Income rate: +${breachRes.income_bonus} cr/sec`);
                        } else {
                            term.writeln(`\x1b[31m[-] ${breachRes.error}`);
                        }
                        break;

                    default:
                        term.writeln(`\x1b[31mUnknown command: ${command}`);
                        term.writeln('\x1b[36mAvailable: status, targets, breach <bssid>, deploy ransomware <bssid> [--type], install miner <bssid>, sniff <bssid>, buy tool <name>, zones\x1b[0m');
                }
            } catch (e) {
                term.writeln(`\x1b[31mError: ${e.message}\x1b[0m`);
            }
        }

        document.getElementById('close-terminal').addEventListener('click', () => {
            document.getElementById('terminal-container').style.display = 'none';
        });

        // Botnet container
        document.getElementById('icon-botnet').addEventListener('dblclick', () => {
            document.getElementById('botnet-container').style.display = 'block';
            fetch('/api/botnet/status').then(r => r.json()).then(data => {
                document.getElementById('owned-count').textContent = data.owned_count;
                document.getElementById('income-rate').textContent = data.total_income_rate;
                document.getElementById('last-payout').textContent = data.last_payout || 'never';
            });
        });

        document.getElementById('close-botnet').addEventListener('click', () => {
            document.getElementById('botnet-container').style.display = 'none';
        });

        document.getElementById('simulate-payout').addEventListener('click', () => {
            fetch('/api/botnet/payout', {method: 'POST'}).then(r => r.json()).then(data => {
                alert(`Payout: +${data.payout} credits!`);
                document.getElementById('last-payout').textContent = new Date().toLocaleTimeString();
            });
        });

        // Market container
        document.getElementById('icon-market').addEventListener('dblclick', () => {
            document.getElementById('market-container').style.display = 'block';
            fetch('/api/market/tools').then(r => r.json()).then(data => {
                const container = document.getElementById('tools-list');
                container.innerHTML = data.tools.map(tool => `
                    <div class="bg-black/50 border border-emerald-500 rounded p-4">
                        <h4 class="text-emerald-400 font-bold">${tool.name}</h4>
                        <p class="text-emerald-600 text-sm mb-2">${tool.description}</p>
                        <p class="text-emerald-300">Cost: ${tool.cost} credits</p>
                        <p class="text-emerald-300">Bonus: x${tool.bonus_multiplier}</p>
                        <button class="mt-2 w-full bg-emerald-900/50 border border-emerald-400 text-emerald-400 py-1 rounded hover:bg-emerald-900/70"
                                onclick="buyTool('${tool.name}')">BUY</button>
                    </div>
                `).join('');
            });
        });

        document.getElementById('close-market').addEventListener('click', () => {
            document.getElementById('market-container').style.display = 'none';
        });

        window.buyTool = async function(toolName) {
            const res = await fetch('/api/market/buy', {
                method: 'POST',
